    methods (Access = private)

        function TDTData = read_TDT_files(app)
            TDTData = TDTbin2mat(app.TDTDir);
            % Define the channels

            channels = fieldnames(TDTData.streams);
            app.isosbesticChannels = [];
            columns = {'channel', 'signalName', 'refChannel', 'samplingRate', 'invert'};
            columnTypes = {'string', 'string', 'string', 'double', 'logical'};
            app.channelInfo = table( ...
                'Size',[4, length(columns)], ...
                'RowNames', app.channelIndex, ...
                'VariableNames', columns, ...
                'VariableTypes', columnTypes ...
            );

            for i = 1:length(channels)
                channel = channels{i};
                % Extract the numeric digits from the channel string
                tokens = regexp(channel, '^x(\d+)([A-D]$)', 'tokens');
                if ~isempty(tokens)
                    wavelength = str2double(tokens{1}{1});
                    channelInd = tokens{1}{2};
                    if wavelength <= 420 % isosbestic channel
                        app.isosbesticChannels = [app.isosbesticChannels channels(i)];
                        app.channelInfo.refChannel(channelInd) = channel;
                    else
                        samplingRate = TDTData.streams.(channel).fs;
                        app.channelInfo.channel(channelInd) = channel;
                        app.channelInfo.samplingRate(channelInd) = samplingRate;
                    end
                end
            end

            % set default refChanne; for B and D
            matchA = find(endsWith(app.isosbesticChannels, 'A'));
            matchC = find(endsWith(app.isosbesticChannels, 'C'));
            % Handle duplicates / missing
            if isempty(matchA)
                error('No isosbestic channel in "A" found for refChannel B.');
            elseif numel(matchA) > 1
                warning('Multiple channels end with "A". Using the first: %s', app.isosbesticChannels{matchA(1)});
            end

            if isempty(matchC)
                error('No isosbestic channel in "C" found for refChannel D.');
            elseif numel(matchC) > 1
                warning('Multiple channels end with "C". Using the first: %s', app.isosbesticChannels{matchC(1)});
            end

            % Assign to app
            app.channelInfo.refChannel('B') = app.isosbesticChannels{matchA(1)};
            app.channelInfo.refChannel('D') = app.isosbesticChannels{matchC(1)};
        end

        function [] = display_TDT_channels(app, TDTData)
            % provide the option for not using a ref channel
            app.isosbesticChannels(end+1) = {'none'};
            for k = 1:numel(app.channelIndex)
                L = app.channelIndex{k};
                editFieldName = sprintf('Channel%sField', L);
                dropDownName = sprintf('RefChannel%sDropDown', L);
                app.(editFieldName).Value = app.channelInfo.channel(L);
                app.(dropDownName).Items = app.isosbesticChannels;
                app.(dropDownName).Value = app.channelInfo.refChannel(L);
            end

            % ttlChan
            ttlChannels = fieldnames(TDTData.epocs);
            ttlChannels{end+1} = 'none';
            app.TTLChannelDropDown.Items = ttlChannels;
            app.TTLChannelDropDown.Value = ttlChannels{1};
            app.EventPeriodChannelDropDown.Items = ttlChannels;
            app.EventPeriodChannelDropDown.Value = ttlChannels{end};
            app.ProgressPanel.Visible = 'off';
            app.ProgressTextArea.Value = {''};
            app.TDTBiosignalsPanel.Visible = 'on';
        end

        function [signalNamesAdded, signalNamesUnique] = add_signal_names(app)
            signalNamesAdded = false;
            signalNamesUnique = true;
            signalNames = strings(numel(app.channelIndex), 1);
            nSignalNames = 0;
            for k = 1:numel(app.channelIndex)
                L = app.channelIndex{k};
                editFieldName = sprintf('Signal%sNameEditField', L);
                checkBoxName = sprintf('Invert%sCheckBox', L);
                sigName = char(lower(strtrim(string(app.(editFieldName).Value))));
                invert = app.(checkBoxName).Value;
                app.channelInfo.signalName(L) = missing;
                app.channelInfo.invert(L) = invert;
                app.(editFieldName).Value = sigName;
                if ~isempty(sigName)
                    app.channelInfo.signalName(L) = sigName;
                    signalNamesAdded = true;
                    nSignalNames = nSignalNames + 1;
                    signalNames(nSignalNames) = sigName;
                end
            end

            if signalNamesAdded
                signalNames = signalNames(1:nSignalNames);
                formattedSignalNames = sanitizeSignalNames(signalNames);
                signalNamesUnique = numel(unique(formattedSignalNames)) == numel(formattedSignalNames);
            end
        end

        function signalsCorrected = process_fp_signal_parallel(app, signals, refSignals, signalsCorrected, signalChannels, invertSignals, onsetFPInd)
            q = parallel.pool.DataQueue;
            afterEach(q, @updateProgress);
            app.ProgressTextArea.Value{end+1} = 'Parallel computing available. Processing in parallel...';
            drawnow
            parfor i = 1:length(signalChannels)
                channel = signalChannels(i);
                refSignal = refSignals(i, :);
                refSignal = refSignal(onsetFPInd:end);
                signal = signals(i, :);
                signal = signal(onsetFPInd:end);
                invert = invertSignals(i);
                signalCorrected = correct_fp_signal(signal, refSignal, 'invert', invert);
                signalsCorrected(i, :) = signalCorrected;
                send(q, channel);
            end

            function updateProgress(channel)
                message = sprintf('Processed signal from %s.', channel);
                app.ProgressTextArea.Value{end+1} = message;
                drawnow
            end
        end

        function signalsCorrected = process_fp_signal(app, signals, refSignals, signalsCorrected, signalChannels, invertSignals, onsetFPInd)
            for i = 1:length(signalChannels)
                channel = signalChannels(i);
                refSignal = refSignals(i, :);
                refSignal = refSignal(onsetFPInd:end);
                signal = signals(i, :);
                signal = signal(onsetFPInd:end);
                invert = invertSignals(i);
                signalCorrected = correct_fp_signal(signal, refSignal, 'invert', invert);
                signalsCorrected(i, :) = signalCorrected;
                message = sprintf('Processed signal from %s.', channel);
                app.ProgressTextArea.Value{end+1} = message;
                drawnow;
            end
        end

        function signalsCorrected = process_fp_signals(app, TDTData)
            ttlChannel = app.TTLChannelDropDown.Value;
            app.ttlOnset = get_fp_onset(TDTData, ttlChannel);

            % extract labels if recorded in a channel in epocs in TDTData
            app.getEvent(TDTData, app.ttlOnset);

            app.fpFrequency = app.channelInfo.samplingRate(1);
            onsetFPInd = max(1, round(app.ttlOnset  *app.fpFrequency));
            app.channelInfo = rmmissing(app.channelInfo, 'DataVariables', 'signalName');
            signalChannels = app.channelInfo.channel;
            invertSignals = app.channelInfo.invert;
            streams = TDTData.streams;
            lengths = cellfun(@(ch) numel(streams.(ch).data), signalChannels);
            signalLength = min(lengths); % sometimes signals from diff chans vary in length

            if any(lengths ~= signalLength)
                lengthsStr = strjoin(string(lengths), ', ');
                message = sprintf('Signal channels differ in length. Min = %d, lengths = [%s]', signalLength, lengthsStr);
                app.ProgressTextArea.Value{end+1} = message;
            end

            %signalLength = length(TDTData.streams.(signalChannels(1)).data);
            app.signalLengthCut = signalLength - onsetFPInd + 1;
            app.nChannel = height(app.channelInfo);
            signals = zeros(app.nChannel, signalLength);
            refSignals = zeros(app.nChannel, signalLength);
            signalsCorrected = zeros(app.nChannel, app.signalLengthCut);
            for i = 1:app.nChannel
                channel = app.channelInfo.channel(i);
                refChannel = app.channelInfo.refChannel(i);
                signals(i,:) = TDTData.streams.(channel).data(1:signalLength);
                refSignals(i, :) = TDTData.streams.(refChannel).data(1:signalLength);
            end

            if length(signalChannels) > 1 && canUseParallelPool
                pool = gcp('nocreate');
                if isempty(pool)
                    parpool(2)
                end
                signalsCorrected = process_fp_signal_parallel(app, signals, refSignals, signalsCorrected, signalChannels, invertSignals, onsetFPInd);
            else
                signalsCorrected = process_fp_signal(app, signals, refSignals, signalsCorrected, signalChannels, invertSignals, onsetFPInd);
            end

        end


        function [] = process_selected_data(app)
            if ~isempty(app.TDTDir)
                app.signalsCorrected = process_fp_signals(app, app.TDTData);
                app.ProgressTextArea.Value{end+1} = 'Done processing data from TDT.';
                drawnow
            end

            if ~isempty(app.EEGPath)
                app.ProgressTextArea.Value{end+1} = 'Processing data from Viewpoint...';
                drawnow
                [app.eeg, app.emg] = process_viewpoint_data(app);
                app.ProgressTextArea.Value{end+1} = 'Done processing data from Viewpoint.';
            end
            app.SaveFileButton.Enable = 'on';
            app.SaveFileButton.Visible = 'on';
        end


        function [eeg, emg] = process_viewpoint_data(app)
            [viewpointData, info] = read_viewpoint_data(app.EEGPath);
            app.eegFrequency = info.Fs;
            [eeg, emg] = align_viewpoint_data(viewpointData, app.eegFrequency);
            eeg_start_time = [info.BinFiles.TStart];
            total_duration = length(eeg) / app.eegFrequency;
        end

        function processedSleepData = save_sleep_data(app)
            signalNames = app.channelInfo.signalName;
            signalNames = sanitizeSignalNames(signalNames);
            processedSleepData = cell2struct(mat2cell(app.signalsCorrected, ones(1,app.nChannel), app.signalLengthCut), cellstr(signalNames'), 1);
            processedSleepData.fp_signal_names = cellstr(signalNames);
            processedSleepData.eeg = app.eeg;
            processedSleepData.emg = app.emg;
            processedSleepData.fp_frequency = app.fpFrequency;
            processedSleepData.ttl_onset = app.ttlOnset;
            processedSleepData.eeg_frequency = app.eegFrequency;
            processedSleepData.event = app.eventData;
        end

        function [] = check_home_panel_input(app)
            if ~isempty(app.subjectID) && (~isempty(app.TDTDir) || ~isempty(app.EEGPath))
                app.ContinueButton.Enable = "on";
            else
                app.ContinueButton.Enable = "off";
            end
        end

        function [] = reset_app(app)
            app.TDTDir = '';
            app.EEGPath = '';
            app.TDTData = [];
            app.loadedTDTDir = '';
            app.HomePanel.Visible = 'on';
            app.ContinueButton.Enable = 'off';
            app.SaveFileButton.Enable = 'off';
            app.SaveFileButton.Visible = 'off';
            app.SubjectIDEditField.Value = '';
            app.SelectedTDTFolderTextArea.Value = '';
            app.SelectedEEGEMGPathTextArea.Value = '';
            app.ttlOnset = 0;
            app.eventData = {};
            app.eventChannel = 'none';
            for k = 1:numel(app.channelIndex)
                L = app.channelIndex{k};
                editFieldName = sprintf('Signal%sNameEditField', L);
                app.(editFieldName).Value = '';
            end
        end


        function [] = getEvent(app, TDTData, ttlOnset)
            if isempty(app.eventData)
                return
            end
            eventOnset = TDTData.epocs.(app.eventChannel).onset; % n x 1 double
            eventOffset = TDTData.epocs.(app.eventChannel).offset; % n x 1 double
            eventTime = [eventOnset eventOffset];
            eventTime = eventTime - ttlOnset;
            app.eventData{2} = eventTime;
            message = sprintf('Processed events from %s.', app.eventChannel);
            app.ProgressTextArea.Value{end+1} = message;
        end
    end


