        % Button pushed function: AddTDTFolderButton
        function AddTDTFolderButtonPushed(app, event)
            f = figure('Position', [-100 -100 0 0]); % create a dummy figure so that uigetfile doesn't minimize our GUI
            selectedDir = uigetdir(app.defaultUigetdir);
            [parentFolder, ~, ~] = fileparts(string(selectedDir));
            app.defaultUigetdir = parentFolder;
            % Check if a directory was selected (uigetdir returns 0 if the user cancels the dialog)
            delete(f);
            if selectedDir ~= 0
                % Store the selected directory path in the Edit Field
                app.SelectedTDTFolderTextArea.Value = selectedDir;
                app.TDTDir = selectedDir; % ValueChaning callback is not triggered if changed programmatically
                check_home_panel_input(app); % so we need to manually check for input
            end

        end

        % Button pushed function: AddViewpointSireniaFileButton
        function AddViewpointSireniaFileButtonPushed(app, event)
            f = figure('Position', [-100 -100 0 0]); % create a dummy figure so that uigetfile doesn't minimize our GUI
            if ~isempty(app.defaultUigetdir)
                [selectedFile, parentFolder] = uigetfile({'*.exp; *.edf;'}, '', app.defaultUigetdir);
            else
            [selectedFile, parentFolder] = uigetfile({'*.exp; *.edf;'});
            end
            app.defaultUigetdir = parentFolder;
            % Check if a directory was selected (uigetdir returns 0 if the user cancels the dialog)
            delete(f);
            if selectedFile ~= 0
                % Store the selected directory path in the Edit Field
                app.SelectedEEGEMGPathTextArea.Value = fullfile(parentFolder, selectedFile);
                app.EEGPath = fullfile(parentFolder, selectedFile); % ValueChaning callback is not triggered if changed programmatically
                check_home_panel_input(app); % so we need to manually check for input
            end

        end

        % Button pushed function: ContinueButton2
        function ContinueButton2Pushed(app, event)
            [signalNameAdded, signalNamesUnique] = add_signal_names(app);
            title = 'Error';
            if ~signalNameAdded
                message = 'Please name at least one signal. Unnamed signals will not be saved.';
                uialert(app.UIFigure, message, title);
                return
            end
            if ~signalNamesUnique
                message = 'Signal names must be unique after formatting.';
                uialert(app.UIFigure, message, title);
                return
            end

            app.eventChannel = app.EventPeriodChannelDropDown.Value;
            if ~strcmp(app.eventChannel, 'none')
                eventName = regexprep(strtrim(app.EventPeriodNameEditField.Value), '\s+', '_');
                if isempty(eventName)
                    message = 'Please name the event/period.';
                    uialert(app.UIFigure, message, title);
                    return
                end
                app.eventData = {eventName, []};
            end

            app.TDTBiosignalsPanel.Visible = 'off';
            app.ProgressPanel.Visible = "on";
            app.ProgressTextArea.Value = {'Processing...'};
            drawnow;
            process_selected_data(app);
        end

        % Button pushed function: ContinueButton
        function ContinueButtonPushed(app, event)
            app.HomePanel.Visible = 'off';
            app.ProgressPanel.Visible = 'on';

            if ~isempty(app.TDTDir)
                pathChanged = isempty(app.loadedTDTDir) || ...
                    ~strcmpi(app.TDTDir, app.loadedTDTDir);
                if pathChanged || isempty(app.TDTData)
                    app.ProgressTextArea.Value = {'Reading TDT data... This may take a minute.'};
                    drawnow;
                    app.TDTData = read_TDT_files(app);
                    app.loadedTDTDir = app.TDTDir;
                    display_TDT_channels(app, app.TDTData);
                else
                    app.ProgressPanel.Visible = 'off';
                    app.TDTBiosignalsPanel.Visible = 'on';
                end
                return
            end

            app.ProgressTextArea.Value = {'Processing data...'};
            drawnow;
            process_selected_data(app);
        end

        % Button pushed function: SaveFileButton
        function SaveFileButtonPushed(app, event)
            f = figure('Position', [-100 -100 0 0]); % create a dummy figure so that uigetfile doesn't minimize our GUI
            %[~, name, ~] = fileparts(string(app.TDTDir));
            defaultSaveName = string(app.subjectID) + '.mat';
            [filename, path, ~] = uiputfile('*.mat', 'Save File', fullfile(app.defaultUigetdir, defaultSaveName));
            % Check if a directory was selected (uigetdir returns 0 if the user cancels the dialog)
            delete(f);
            if path ~= 0
                app.ProgressTextArea.Value{end+1} = 'Saving sleep data...';
                app.SaveFileButton.Enable = 'off';
                drawnow
                full_file_path = fullfile(path, filename);
                full_file_path = string(full_file_path);
                processedSleepData = save_sleep_data(app);
                save(full_file_path, '-struct', 'processedSleepData');

                message = strcat("Processed signals saved to ", full_file_path);
                title = 'File Saved';
                icon = 'success';
                uialert(app.UIFigure, message, title, 'Icon', icon);
                reset_app(app)
            end
        end

