        end

        % Button pushed function: BackButton
        function BackButtonPushed(app, event)
            app.TDTBiosignalsPanel.Visible = 'off';
            app.HomePanel.Visible = 'on';
        end

        % Value changed function: EventPeriodChannelDropDown
        function EventPeriodChannelDropDownValueChanged(app, event)
            value = app.EventPeriodChannelDropDown.Value;
            if strcmp(value, 'none')
                app.EventPeriodNameEditField.Visible = "off";
                app.EventPeriodNameLabel.Visible = 'off';
            else
                app.EventPeriodNameEditField.Visible = "on";
                app.EventPeriodNameLabel.Visible = 'on';
            end
        end
    end

